import "./App.css";
import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import Gallery from "./components/Gallery";
import Cart from "./components/Cart";
import Payment from "./components/Payment";
import Contact from "./components/Contact";
import Confirmation from "./components/Confirmation";
import Mission from "./components/Mission";
import Footer from "./components/Footer";  // ✅ Import du Footer
/* Ajout pour les toasts */
import { ToastContainer } from "react-toastify";



function App() {
  const [cart, setCart] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };
  const closeMenu = () => {
    setMenuOpen(false);
  };

  return (
    <Router>
      <div>
        {/* Navigation */}
        <nav className="navbar">
          <div className="nav-logo">Galerie d'Art Inclusif</div>
          <div className={`burger ${menuOpen ? "open" : ""}`} onClick={toggleMenu}>
            <span></span>
            <span></span>
            <span></span>
          </div>
          <div className={`nav-links ${menuOpen ? "open" : ""}`}>
            <Link to="/" onClick={closeMenu}>Accueil</Link>
            <Link to="/gallery" onClick={closeMenu}>Galerie</Link>
            <Link to="/cart" onClick={closeMenu} className="cart-link">🛒 Panier{cart.length > 0 && (<span key={cart.length} className="cart-badge">{cart.length}</span>)}
            </Link>
            <Link to="/contact" onClick={closeMenu}>Contact</Link>
            <Link to="/mission" onClick={closeMenu}>Notre Mission</Link>
          </div>
        </nav>

        {/* Contenu des pages */}
        <div className="page-content">
          <Routes>
            <Route
  path="/"
  element={
    <div style={{ textAlign: "center", padding: "40px" }}>
      <h1 style={{ color: "#FFD700" }}>Bienvenue dans la Galerie</h1>
       <p>
        Découvrez les œuvres d'artistes talentueux en situation de handicap et
        soutenez leur créativité. Nous offrons une plateforme pour exposer et
        vendre les œuvres d'artistes en situation de handicap psychique sur
        Grenoble en Isère. Rejoignez-nous pour célébrer la diversité et
        encourager ces talents incroyables. Notre objectif est de rendre l'art
        accessible à tous...
      </p>
    </div>
  }
/>
          
            <Route path="/gallery" element={<Gallery cart={cart} setCart={setCart} />} />
            <Route path="/cart" element={<Cart cart={cart} setCart={setCart} />} />
            <Route path="/payment" element={<Payment cart={cart} setCart={setCart} />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/confirmation" element={<Confirmation />} />
            <Route path="/mission" element={<Mission />} />
          </Routes>
          <ToastContainer />
        </div>

        {/* ✅ Footer affiché sur toutes les pages */}
        <Footer />
      </div>
    </Router>
  );
}

export default App;
